export function getTranslatedSlug(esSlug: string, lang: string): string {
  if (lang === "es") return esSlug;
  return BLOG_SLUG_I18N[esSlug]?.[lang as SupportedLang] || esSlug;
}

const reverseCache: Record<string, Record<string, string>> = {};

function buildReverseCache(lang: string): Record<string, string> {
  if (reverseCache[lang]) return reverseCache[lang];
  const map: Record<string, string> = {};
  for (const [esSlug, translations] of Object.entries(BLOG_SLUG_I18N)) {
    const translated = translations[lang as SupportedLang];
    if (translated) map[translated] = esSlug;
  }
    for (const [oldSlug, entry] of Object.entries(BLOG_SLUG_LEGACY_I18N)) {
    if (entry.lang === lang) map[oldSlug] = entry.es;
  }
  reverseCache[lang] = map;
  return map;
}

export function resolveToSpanishSlug(slug: string, lang: string): string {
  if (lang === "es") return slug;
  const map = buildReverseCache(lang);
  return map[slug] || slug;
}
